QueryScript.Source:
            
                      import sailpoint.tools.Util;
                      import java.util.List;
                      import java.util.ArrayList;
                      import org.apache.log4j.Logger;
                      import sailpoint.object.Link;
                      import sailpoint.object.QueryOptions;
                      import sailpoint.object.Filter;

                     
                      Filter finalFilter;
                      Filter filter;
                      QueryOptions queryOptions = null;
                      List idType = new ArrayList();
                      idType.add("Contractor");

                      if (value==null){

                      } else {
                     
                      List businessUnitsList = new ArrayList();
                      List departmentNumberList = new ArrayList();

                      for (String bUnitAndDeptNo : value){
                      String[] str = bUnitAndDeptNo.split("\\.");
                      String businessUnit = str[0];   
                      String departmentNumber = str[1].trim();
                      businessUnitsList.add(businessUnit);
                      departmentNumberList.add(departmentNumber);
                      }
			          queryOptions = new QueryOptions();
                      Filter filter = Filter.ignoreCase(Filter.and(Filter.eq("identity.inactive",false),Filter.in("identity.type",idType),
					  Filter.in("identity.departmentNumber",departmentNumberList),
                      Filter.in("identity.businessUnit",businessUnitsList)));
                      queryOptions.addFilter(filter);
                      }
                      return queryOptions;

