                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;
                    import org.apache.log4j.Logger;
					Link link = context.getObjectById(Link.class, value);
                    String sAMAccountName = link.getAttribute("sAMAccountName");
                    return sAMAccountName;

                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;
                    import org.apache.log4j.Logger;

                    Link link = context.getObjectById(Link.class, value);
                    String accountExpires = link.getAttribute("accountExpires");
                    String expirationDate = null;

                    try{
                    if (null != accountExpires && !accountExpires.isEmpty()){
                    if (accountExpires.equalsIgnoreCase("never")){
                    expirationDate = accountExpires;
                    }else{
                    futureAccExpiration = Util.stringToDate(accountExpires);
                    expirationDate = Util.dateToString(futureAccExpiration,"MM/dd/yyyy");
                    }
                    }
                    }catch(Exception pe){
                    log.debug("inside catch block Exception : " + pe);
                    }
                    
                    return expirationDate;
